    id: 'transfer',
    group: 'human',
    title: 'The Resolving Power of Transfer Experiments: When Can Designs Distinguish Accounts of Generalization?',
    text: 'transfer experiments generalization computational models SLR Lab human learning'
  },
  {
    id: 'encoding',
    group: 'human',
    title: 'Functional Encoding and Representational Binding in Componential Transfer',
    text: 'functional encoding representational binding componential transfer SLR Lab human learning'
  },
  {
    id: 'smoothLearningCurve',
    group: 'human',
    title: 'When Does a Smooth Learning Curve Mean Smooth Learning? Representational Format, Identifiability, and the Bounded Averaging Artifact',
    text: 'smooth learning curve representational format identifiability bounded averaging artifact human statistical learning'
  },
  {
    id: 'priorsPersist',
    group: 'lm',
    title: 'Priors Persist Through Suppression: A Stroop Paradigm for Lexical Override',
    text: 'language models priors suppression stroop lexical override model internals causal intervention'
  },
  {
    id: 'functionVector',
    group: 'lm',
    title: 'Function-Vector Heads Are Two Populations: Writers and Cancellers in In-Context Learning',
    text: 'function vectors attention heads writers cancellers in-context learning interpretability'
  },
  {
    id: 'bright',
    group: 'lm',
    title: 'BRIGHT: A Realistic and Challenging Benchmark for Reasoning-Intensive Retrieval',
    text: 'BRIGHT benchmark reasoning intensive retrieval XLANG ICLR'
  },
  {
    id: 'cognitiveGovernance',
    group: 'humanAi',
    title: 'When Representation Outruns Uptake: Cognitive Governance in LLM-Assisted Writing',
    text: 'human AI interaction collaboration writing cognitive governance cognitive uptake agency representation LLM assisted writing'
  },
  {
    id: 'humansDisengage',
    group: 'humanAi',
    title: 'Humans Disengage, Reasoning Models Persist: Separating Difficulty Registration from Deliberation Allocation',
    text: 'humans reasoning models comparison deliberation allocation difficulty registration disengagement control policies'
  }
];

export default {
  name: 'ResearchTab',
  mixins: [scrollRevealMixin],
  data() {
    return {
      introExpanded: false,
      expanded: { human: true, lm: true, humanAi: true },
      searchQuery: '',
      pubDesc: publicationDescriptions,
      researchEntries
    };
  },
  computed: {
    searchTerms() {
      return this.searchQuery
        .toLowerCase()
        .split(/[\s,.;:!?()[\]{}"']+/)
        .map((term) => term.trim())
        .filter((term) => term.length >= 2);
    },
    searchActive() {
      return this.searchTerms.length > 0;
    },
    hasSearchMatches() {
      return this.researchEntries.some((entry) => this.entryMatches(entry.id));
    }
  },
  watch: {
    searchQuery() {
      this.refreshScrollReveal();
    }
  },
  methods: {
    stripHtml(text) {
      return String(text || '').replace(/<[^>]+>/g, ' ');
    },
    escapeHtml(text) {
      return String(text == null ? '' : text)
        .split('&').join('&amp;')
        .split('<').join('&lt;')
        .split('>').join('&gt;')
        .split(String.fromCharCode(34)).join('&quot;')
        .split("'").join('&#39;');
    },
    escapeRegExp(text) {
      return String(text).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    },
    highlightTerms(text) {
      const terms = [...new Set(this.searchTerms)]
        .sort((a, b) => b.length - a.length)
        .map((term) => this.escapeRegExp(term));
      if (!terms.length) return text;

      const re = new RegExp(`(${terms.join('|')})`, 'gi');
      return String(text).replace(re, '<mark>$1</mark>');
    },
    highlightText(text) {
      return this.highlightTerms(this.escapeHtml(text));
    },
    highlightHtml(html) {
      const parts = String(html || '').split(/(<[^>]+>)/g);
      return parts
        .map((part) => (part.startsWith('<') && part.endsWith('>') ? part : this.highlightTerms(part)))
        .join('');
    },
    entryById(id) {
      return this.researchEntries.find((entry) => entry.id === id);
    },
    entrySearchText(entry) {
      return [
        entry.title,
        entry.text,
        this.stripHtml(this.pubDesc[entry.id])
      ].join(' ').toLowerCase();
    },
    entryMatches(id) {
      const entry = this.entryById(id);
      if (!entry) return false;
      const text = this.entrySearchText(entry);
      return this.searchTerms.every((term) => text.includes(term));
    },
    groupMatches(groupKey) {
      return this.researchEntries
        .filter((entry) => entry.group === groupKey)
        .some((entry) => this.entryMatches(entry.id));
    },
    groupVisible(groupKey) {
      if (!this.searchActive) return true;
      return this.groupMatches(groupKey);
    },
    isGroupExpanded(groupKey) {
      if (this.searchActive) return this.groupMatches(groupKey);
      return this.expanded[groupKey];
    },
    entryVisible(id) {
      if (!this.searchActive) return true;
      return this.entryMatches(id);
    },
    toggleIntro() {
      const wasExpanded = this.introExpanded;
      this.introExpanded = !this.introExpanded;
      this.$nextTick(() => {
        this.refreshScrollReveal();
        if (wasExpanded && this.$refs.researchTop) {
          this.$refs.researchTop.scrollIntoView({
            behavior: 'smooth',
            block: 'start'
          });
        }
      });
    },
    toggleGroup(groupKey) {
      if (this.searchActive) return;
      this.expanded = {
        ...this.expanded,
        [groupKey]: !this.expanded[groupKey]
      };
      this.refreshScrollReveal();
    },
    clearSearch() {
      this.searchQuery = '';
    }
  }
}
</script>

