<script>
import scrollRevealMixin from '../mixins/scrollRevealMixin';
import EmbeddingMap from './EmbeddingMap.vue';
import { loadSearchItems, lexicalRank, rrfFuse } from '../utils/askRetrieval';
import { ensureReady, semanticScores, SCORE_FLOOR } from '../utils/semanticSearch';

export default {
  name: 'SearchStoryPage',
  components: { EmbeddingMap },
  mixins: [scrollRevealMixin],
  data() {
    return {
      labQuery: '',
      labBusy: false,
      labStatus: '',
      labSamples: ['learning new words every day', 'HSBC', 'where has Henry lived?'],
      lexTop: [],
      semTop: [],
      fusedTop: [],
      scores: [],
      floor: SCORE_FLOOR,
      defaultFloor: SCORE_FLOOR,
      corpusSize: 0,
    };
  },
  computed: {
    passCount() {
      return this.scores.filter((s) => s >= this.floor).length;
    },
  },
  mounted() {
    loadSearchItems().then((items) => { this.corpusSize = items.length; }).catch(() => {});
  },
  methods: {
    scoreX(s) {
      const lo = -0.05;
      const hi = 0.7;
      return Math.max(0, Math.min(100, ((s - lo) / (hi - lo)) * 100));
    },
    cleanTitle(t) {
      return String(t || '').replace(/\s+\(\d+\)$/, '');
    },
    async runLab() {
      const q = this.labQuery.trim();
      if (!q || this.labBusy) return;
      this.labBusy = true;
      this.labStatus = 'Warming up the on-device model (the first run downloads it to your browser)…';
      try {
        const items = await loadSearchItems();
        this.corpusSize = items.length;
        const byId = {};
        for (const it of items) byId[it.id] = it;

        await ensureReady();
        this.labStatus = '';
        const all = await semanticScores(q);
        const lex = lexicalRank(q, items);
        const fusedIds = rrfFuse(lex, all.slice(0, 12).map((h) => ({ id: h.id }))).slice(0, 8);

        const lexRank = new Map(lex.map((x, i) => [x.id, i + 1]));
        const semRank = new Map(all.map((x, i) => [x.id, i + 1]));
        const maxLex = lex.length ? lex[0].s : 1;
        const maxSem = all.length ? Math.max(all[0].score, 0.001) : 1;

        this.lexTop = lex.slice(0, 5).map((x) => ({
          id: x.id,
          title: this.cleanTitle(byId[x.id] && byId[x.id].title),
          pct: Math.round((x.s / maxLex) * 100),
        }));
        this.semTop = all.slice(0, 5).map((x) => ({
          id: x.id,
          title: this.cleanTitle(byId[x.id] && byId[x.id].title),
          pct: Math.round((Math.max(x.score, 0) / maxSem) * 100),
        }));
        this.fusedTop = fusedIds.slice(0, 5).map((id) => ({
          id,
          title: this.cleanTitle(byId[id] && byId[id].title),
          badge: `${lexRank.has(id) ? 'L' + lexRank.get(id) : 'L–'} · S${semRank.get(id)}`,
        }));
        this.scores = all.map((x) => x.score);
      } catch (e) {
        this.labStatus = 'The model could not load right now. Try again in a moment.';
      } finally {
        this.labBusy = false;
      }
    },
    openSearchPalette() {
      window.dispatchEvent(new KeyboardEvent('keydown', {
        key: '/',
        bubbles: true,
        cancelable: true,
      }));
    },
  },
};
</script>

