import { ensureReady, semanticTopK } from './semanticSearch';

const STOP = new Set([
  'the', 'a', 'an', 'of', 'on', 'in', 'to', 'is', 'are', 'was', 'were', 'be',
  'and', 'or', 'for', 'with', 'at', 'by', 'from', 'as', 'it', 'i', 'my', 'me',
  'this', 'that', 'how', 'what', 'we', 'you', 'they', 'but', 'so', 'if', 'into',
  'about', 'out', 'up', 'over', 'than', 'then', 'has', 'have', 'had', 'do',
]);

let itemsPromise = null;

export function searchTokens(query) {
  const all = String(query).toLowerCase().split(/\s+/)
    .map(t => t.replace(/[^\w]+/g, ''))
    .filter(t => t.length >= 2);
  const meaningful = all.filter(t => !STOP.has(t));
  return meaningful.length ? meaningful : all;
}

export async function loadSearchItems() {
  if (!itemsPromise) {
    itemsPromise = fetch('/assets/search-index.json', { cache: 'no-cache' })
      .then((res) => {
        if (!res.ok) throw new Error(`search-index.json ${res.status}`);
        return res.json();
      });
  }
  return itemsPromise;
}

// TF-IDF-flavoured lexical ranking over the search chunks. Exported so the
// search-story page can show this stage of the pipeline on its own.
export function lexicalRank(query, items) {
  const toks = [...new Set(searchTokens(query))].filter(t => t.length >= 3);
  const N = items.length;
  const hays = items.map(it => ({ id: it.id, hay: `${it.title} ${it.body}`.toLowerCase() }));
  const df = {};
  for (const t of toks) df[t] = hays.filter(h => h.hay.includes(t)).length;
  return hays.map(h => {
    let s = 0;
    for (const t of toks) if (df[t] > 0 && h.hay.includes(t)) s += Math.log(1 + N / df[t]);
    return { id: h.id, s };
  }).filter(x => x.s > 0).sort((a, b) => b.s - a.s);
}

// Weighted reciprocal-rank fusion of the two rankings, with the top lexical
// hits pinned first. Returns fused ids, best first.
export function rrfFuse(lex, sem, { K = 60, lexWeight = 2, semWeight = 1, forceLex = 3 } = {}) {
  const score = new Map();
  const add = (arr, w) => arr.forEach((x, i) => score.set(x.id, (score.get(x.id) || 0) + w / (K + i)));
  add(lex, lexWeight);
  add(sem, semWeight);
  const rrf = [...score.entries()].sort((a, b) => b[1] - a[1]).map(([id]) => id);
  const forced = lex.slice(0, forceLex).map(x => x.id);
  return [...new Set([...forced, ...rrf])];
}

export async function retrieveAskContexts(query, n = 8, existingItems) {
  const items = existingItems && existingItems.length ? existingItems : await loadSearchItems();
  const itemsById = {};
  for (const it of items) itemsById[it.id] = it;

  await ensureReady();
  const sem = await semanticTopK(query, 12);
  const lex = lexicalRank(query, items);
  const ids = rrfFuse(lex, sem.map(h => ({ id: h.id }))).slice(0, n);
  return ids.map(id => itemsById[id]).filter(Boolean);
}

function isFragmentItem(item) {
  return item && item.route === '/fragments';
}

export function sourceDisplayTitle(source) {
  const title = String(source?.title || source?.page || 'Untitled')
    .replace(/\s+\(\d+\)$/, '')
    .replace(/\s+\/\s+[\u3400-\u9fff].*$/, '')
    .trim();
  return title || 'Untitled';
}

export function sourceKey(source) {
  return `${source?.route || ''}#${source?.anchor || sourceDisplayTitle(source)}`;
}

export function normalizeAskSource(source) {
  const normalized = {
    ...source,
    title: sourceDisplayTitle(source),
  };
  return {
    ...normalized,
    id: sourceKey(normalized),
  };
}

function currentAskInputText(preferPalette = false) {
  if (typeof document === 'undefined') return '';
  const selector = preferPalette
    ? '.sp-input, #homeAsk .home-ask-input'
    : '#homeAsk .home-ask-input, .sp-input';
  const input = document.querySelector(selector);
  return input && 'value' in input ? String(input.value || '') : '';
}

function normalizeAllAskArgs(query, existingItems) {
  const firstArgIsItems = Array.isArray(query);
  const items = firstArgIsItems ? query : existingItems;
  let actualQuery = typeof query === 'string' ? query : '';
  if (!actualQuery) actualQuery = currentAskInputText(firstArgIsItems);
  return { actualQuery, items, firstArgIsItems };
}

export async function allAskContexts(query = '', existingItems) {
  const { actualQuery, items: existing, firstArgIsItems } = normalizeAllAskArgs(query, existingItems);
  const items = existing && existing.length ? existing : await loadSearchItems();
  const base = items.filter(it => !isFragmentItem(it)).sort((a, b) => (a.id || 0) - (b.id || 0));
  const fragments = items.filter(isFragmentItem).sort((a, b) => (a.id || 0) - (b.id || 0));

  if (!actualQuery) return firstArgIsItems ? [...base, ...fragments] : base;

  const retrieved = await retrieveAskContexts(actualQuery, 12, items);
  const fragmentHits = retrieved.filter(isFragmentItem);
  return [...base, ...fragmentHits];
}

export function cleanAskContextText(body) {
  return String(body || '')
    .replace(/^(Research papers[^.]*\.\s*|Hobby, hobbies[^.]*\.\s*)+/i, '')
    .replace(/\s*Years:\s*[\d\s]+\.?\s*$/i, '')
    .trim();
}

export function stripAnswerCitations(answer) {
  return String(answer || '')
    .replace(/\s*,?\s*\bas\s+(?:mentioned|shown|described|noted|stated|indicated|covered|referenced)\s+(?:in|by)\s*(?:\[[\d,\s]+\]\s*(?:(?:,|\band\b|\bor\b)\s*)?)+(?!\w)/gi, '')
    .replace(/\b(?:as\s+)?(?:mentioned|shown|described|noted|stated|indicated|covered|referenced)\s+(?:in|by)\s*(?:\[[\d,\s]+\]\s*(?:(?:,|\band\b|\bor\b)\s*)?)+,?\s*/gi, '')
    .replace(/\s*(?:\[[\d,\s]+\]\s*(?:(?:,|\band\b|\bor\b)\s*)?){2,}/gi, '')
    .replace(/\s*\[[\d,\s]+\]/g, '')
    .replace(/\s*\[[\d,\s]*$/g, '')
    .replace(/\b(?:as\s+)?(?:mentioned|shown|described|noted|stated|indicated|covered|referenced)\s+(?:in|by)\s+(?:and|or)(?=[\s,.!?]|$)/gi, '')
    .replace(/(?:,\s*){2,}/g, ', ')
    .replace(/,+\s*([.!?])/g, '$1')
    .replace(/([.!?]),(\s|$)/g, '$1$2')
    .replace(/\s+([,.!?])/g, '$1')
    .replace(/,\s*$/g, '')
    .trim();
}

export function citedSourcesFromAnswer(answer, sources) {
  const numbered = sources.map((s, i) => ({ ...s, n: i + 1 }));
  const cited = new Set();
  const re = /\[([\d,\s]+)\]/g;
  let m;
  while ((m = re.exec(answer))) {
    m[1].split(/[\s,]+/).filter(Boolean).forEach((n) => cited.add(parseInt(n, 10)));
  }
  if (!cited.size) return [];

  const out = [];
  const seen = new Set();
  for (const source of numbered) {
    if (!cited.has(source.n)) continue;
    const normalized = normalizeAskSource(source);
    const key = sourceKey(normalized);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(normalized);
  }
  return out;
}
