<template>
  <div class="container">
    <div class="scroll-progress" v-show="showScrollProgress" :style="{ transform: 'scaleX(' + scrollPct + ')' }"></div>
    <header class="header" :class="{ 'home-direct-nav': directHomeNavHidden }" v-show="!cvChromeHidden">
      <h3 class="header-title">
        <router-link to="/home">H.W.</router-link>
        <small class="header-subtitle">An enthusiastic explorer</small>
        <div class="menu">
          <nav class="menu-content" :class="'nav-tabs-' + navTabsLayout">
            <router-link to="/about" class="menu-item about">About</router-link>
            <router-link to="/education" class="menu-item education">Study</router-link>
            <router-link to="/experience" class="menu-item experience">Work</router-link>
            <router-link to="/research" class="menu-item research">Research</router-link>
            <router-link to="/projects" class="menu-item projects">Builds</router-link>
            <router-link to="/fragments" class="menu-item fragments">Fragments</router-link>
          </nav>
          <nav class="social-icons">
            <a class="search-trigger" title="Ask or search (⌘K)" aria-label="Ask or search the site" @click="openSearch"><i class="fa fa-search" aria-hidden="true" style="margin-right: 4px;"></i></a>
            <a id="toggle-theme" title="Toggle Theme"><i class="fa fa-sun" aria-hidden="true" style="margin-right: 4px; margin-left: 4px;"></i></a>
            <a id="music-icon" title="Play Music"><i class="fa fa-compact-disc" aria-hidden="true" style="margin-left: 4px;"></i></a>
          </nav>
        </div>
        <audio id="background-music"></audio>
      </h3>
    </header>
    <div class="content-container">
      <router-view v-slot="{ Component }">
        <transition :name="routeTransitionName" mode="out-in" @before-enter="beforeRouteEnter">
          <component :is="Component" />
        </transition>
      </router-view>
    </div>
    <footer class="footer" :class="{ 'home-direct-nav': directHomeNavHidden }" v-show="!cvChromeHidden">
      <a href="https://www.instagram.com/henry_w_hy/" target="_blank">
        <i class="fab fa-instagram" aria-hidden="true"></i>
      </a>
      <a href="https://www.linkedin.com/in/henrywhy/" target="_blank">
        <i class="fab fa-linkedin" aria-hidden="true"></i>
      </a>
      <a href="https://github.com/henryhyw/" target="_blank">
        <i class="fab fa-github" aria-hidden="true"></i>
      </a>
      <router-link to="/cv" title="CV" aria-label="CV">
        <i class="far fa-file-alt" aria-hidden="true"></i>
      </router-link>
      <router-link to="/travels" class="footer-compass" title="Travels" aria-label="Travels">
        <i class="far fa-compass" aria-hidden="true"></i>
      </router-link>
      <div class="footer-description">
        <a><router-link to="/home">H.W. | An enthusiastic explorer</router-link></a>
      </div>
    </footer>
    <SearchPalette ref="search" />
  </div>
</template>

<script>
import SearchPalette from './components/SearchPalette.vue';

export default {
  name: 'App',
  components: { SearchPalette },
  data() {
    return {
      scrollPct: 0,
      navTabsLayout: 'one',
      cvChromeHidden: false,
      directHomeNavHidden:
        typeof window !== 'undefined'
        && /^#\/home(?:$|[?#])/.test(window.location.hash || ''),
    };
  },
  computed: {
    isCv() {
      return this.$route.path === '/cv';
    },
    showScrollProgress() {
      return !this.isCv && this.$route.path !== '/home' && this.$route.path !== '/';
    },
    routeTransitionName() {
      return 'fade-slide';
    }
  },
  watch: {
    isCv(onCv, wasCv) {
      if (this._cvChromeRevealTimer) {
        clearTimeout(this._cvChromeRevealTimer);
        this._cvChromeRevealTimer = null;
      }
      if (onCv) {
        this.pauseMusicForCv();
      } else if (wasCv || this.cvChromeHidden) {
        this._cvChromeRevealTimer = setTimeout(() => {
          this._cvChromeRevealTimer = null;
          if (!this.isCv) {
            this.cvChromeHidden = false;
            this.$nextTick(() => this.scheduleNavTabsLayout({ retries: 4 }));
          }
        }, 280);
      }
    }
  },
  mounted() {
    this.script1 = document.createElement('script');
    this.script1.src = '/assets/js/default.js';
    this.script1.async = true;
    document.body.appendChild(this.script1);
    this.script2 = document.createElement('script');
    this.script2.src = '/assets/js/theme-toggle.js';
    this.script2.async = true;
    document.body.appendChild(this.script2);
    if (this.isCv) {
      this.cvChromeHidden = true;
      this.$nextTick(this.pauseMusicForCv);
    }
    this._onScroll = this.handleScroll;
    window.addEventListener('scroll', this._onScroll, { passive: true });
    this.handleScroll();

    this._onDirectHomeNavRevealed = () => {
      this.directHomeNavHidden = false;
    };
    window.addEventListener('home-direct-nav-revealed', this._onDirectHomeNavRevealed);
    this._onResize = () => this.scheduleNavTabsLayout();
    window.addEventListener('resize', this._onResize, { passive: true });
    this.$nextTick(this.scheduleNavTabsLayout);
    if (document.fonts && document.fonts.ready) {
      document.fonts.ready.then(this.scheduleNavTabsLayout).catch(() => {});
    }
  },
  unmounted() {
    window.removeEventListener('scroll', this._onScroll);
    window.removeEventListener('home-direct-nav-revealed', this._onDirectHomeNavRevealed);
    window.removeEventListener('resize', this._onResize);
    if (this._navLayoutRaf) {
      cancelAnimationFrame(this._navLayoutRaf);
      this._navLayoutRaf = null;
    }
    if (this._cvChromeRevealTimer) {
      clearTimeout(this._cvChromeRevealTimer);
      this._cvChromeRevealTimer = null;
    }
    // Clean up the scripts when the component is destroyed
    if (this.script1 && this.script1.parentNode) {
      this.script1.parentNode.removeChild(this.script1);
    }
    if (this.script2 && this.script2.parentNode) {
      this.script2.parentNode.removeChild(this.script2);
    }
  },
  methods: {
    beforeRouteEnter(el) {
      const enteringCv = el && el.classList && el.classList.contains('cv-root');
      this.cvChromeHidden = enteringCv;
      if (!enteringCv) {
        this.$nextTick(() => this.scheduleNavTabsLayout({ retries: 4 }));
      }
    },
    openSearch() {
      this.$refs.search.openPalette();
    },
    handleScroll() {
      const el = document.documentElement;
      const max = el.scrollHeight - el.clientHeight;
      this.scrollPct = max > 0 ? Math.min(Math.max(el.scrollTop / max, 0), 1) : 0;
    },
    scheduleNavTabsLayout(options = {}) {
      const retries = options.retries || 0;
      if (this._navLayoutRaf) cancelAnimationFrame(this._navLayoutRaf);
      this._navLayoutRaf = requestAnimationFrame(() => {
        this._navLayoutRaf = null;
        const updated = this.updateNavTabsLayout();
        if (!updated && retries > 0) {
          this.scheduleNavTabsLayout({ retries: retries - 1 });
        }
      });
    },
    updateNavTabsLayout() {
      if (this.cvChromeHidden) return false;

      const header = this.$el && this.$el.querySelector('.header');
      const menu = this.$el && this.$el.querySelector('.menu');
      const tabs = this.$el && this.$el.querySelector('.menu-content');
      const icons = this.$el && this.$el.querySelector('.social-icons');
      if (!header || !menu || !tabs || !icons) return false;
      if (getComputedStyle(header).display === 'none') return false;

      const items = Array.from(tabs.querySelectorAll('.menu-item'));
      if (items.length !== 6) return false;

      const menuWidth = menu.getBoundingClientRect().width;
      const widths = items.map((item) => item.getBoundingClientRect().width);
      const iconsWidth = icons.getBoundingClientRect().width;
      if (menuWidth <= 0 || iconsWidth <= 0 || widths.some((width) => width <= 0)) {
        return false;
      }

      const gap = parseFloat(getComputedStyle(tabs).columnGap) || 0;
      const availableWidth = Math.max(0, menuWidth - iconsWidth);
      const layoutWidth = (cols) => {
        const colWidths = Array.from({ length: cols }, (_, col) => {
          let max = 0;
          for (let i = col; i < widths.length; i += cols) {
            max = Math.max(max, widths[i]);
          }
          return max;
        });
        return colWidths.reduce((sum, width) => sum + width, 0) + gap * (cols - 1);
      };

      if (layoutWidth(6) <= availableWidth) {
        this.navTabsLayout = 'one';
      } else if (layoutWidth(3) <= availableWidth) {
        this.navTabsLayout = 'two';
      } else {
        this.navTabsLayout = 'three';
      }
      return true;
    },
    pauseMusicForCv() {
      const music = document.getElementById('background-music');
      const musicIcon = document.getElementById('music-icon');
      if (!music) {
        return;
      }

      music.pause();
      localStorage.setItem('musicPlaying', 'false');
      if (music.currentTime) {
        localStorage.setItem('musicTime', music.currentTime);
      }

      const icon = musicIcon && musicIcon.querySelector('i');
      if (icon) {
        icon.classList.remove('fa-spin');
      }
      if (musicIcon) {
        musicIcon.title = 'Play Music';
      }
    }
  }
}
</script>

<style>
    @import url('./assets/css/main.css');
    @import url('./assets/css/syntax.css');
    @import url('./assets/css/dark-theme.css');
</style>

