// Client for the "Ask this site" generation endpoints.
//
// The EdgeOne fallback is RETIRED: every request now goes to the Cloudflare
// Worker only. The fallback machinery below (probing, retries, endpoint lists)
// is kept intact but never engaged, gated behind EDGEONE_FALLBACK_RETIRED, so
// it can be switched back on later without rewriting anything.
//
// Because there is no fallback, a failed request is surfaced with a message that
// depends on the visitor's likely region: mainland visitors (where the Worker is
// often unreachable) are told it is a regional restriction; everyone else is
// asked to retry.

const DEFAULT_ENDPOINT = process.env.VUE_APP_ASK_ENDPOINT || 'https://ask-henry.whenry6688.workers.dev';
const DEFAULT_FALLBACK_ENDPOINTS = process.env.VUE_APP_ASK_EDGEONE_ENDPOINTS || process.env.VUE_APP_ASK_EDGEONE_ENDPOINT || 'https://ask-cn.henryw.me/api/ask,https://personalpage.edgeone.cool/api/ask';
const PRIMARY_PROBE_TIMEOUT_MS = Number(process.env.VUE_APP_ASK_PRIMARY_PROBE_TIMEOUT_MS || 900);
const ASK_POST_TIMEOUT_MS = Number(process.env.VUE_APP_ASK_POST_TIMEOUT_MS || 18000);
const FALLBACK_POST_RETRIES = Number(process.env.VUE_APP_ASK_FALLBACK_POST_RETRIES || 3);
const FALLBACK_RETRY_DELAY_MS = Number(process.env.VUE_APP_ASK_FALLBACK_RETRY_DELAY_MS || 300);
const FALLBACK_REGION_MODE = process.env.VUE_APP_ASK_FALLBACK_REGION || 'auto';
const MAINLAND_TIME_ZONES = new Set([
  'Asia/Shanghai',
  'Asia/Chongqing',
  'Asia/Harbin',
  'Asia/Urumqi',
  'Asia/Kashgar',
]);

function cleanEndpoint(value) {
  return String(value || '').trim().replace(/\/+$/, '');
}

function parseEndpointList(value) {
  const raw = String(value || '').trim();
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) return parsed.map(cleanEndpoint).filter(Boolean);
  } catch {
    // Fall back to comma-separated parsing.
  }
  return raw.split(',').map(cleanEndpoint).filter(Boolean);
}

function endpoints() {
  try {
    const explicitList = parseEndpointList(localStorage.getItem('askEndpoints'));
    if (explicitList.length) return [...new Set(explicitList)];

    const primary = cleanEndpoint(localStorage.getItem('askEndpoint') || DEFAULT_ENDPOINT);
    const fallbackList = parseEndpointList(localStorage.getItem('askFallbackEndpoints'));
    const singleFallback = cleanEndpoint(localStorage.getItem('askFallbackEndpoint'));
    const fallbacks = fallbackList.length ? fallbackList : parseEndpointList(singleFallback || DEFAULT_FALLBACK_ENDPOINTS);
    return [...new Set([primary, ...fallbacks].filter(Boolean))];
  } catch {
    return [...new Set([cleanEndpoint(DEFAULT_ENDPOINT), ...parseEndpointList(DEFAULT_FALLBACK_ENDPOINTS)].filter(Boolean))];
  }
}

export function askConfigured() {
  return endpoints().length > 0;
}

function fallbackRegionMode() {
  try {
    return String(localStorage.getItem('askFallbackRegion') || FALLBACK_REGION_MODE).trim().toLowerCase();
  } catch {
    return FALLBACK_REGION_MODE;
  }
}

function browserTimeZone() {
  try {
    return Intl.DateTimeFormat().resolvedOptions().timeZone || '';
  } catch {
    return '';
  }
}

function shouldProbePrimaryForFallback() {
  const mode = fallbackRegionMode();
  if (['cn', 'china', 'mainland', 'edgeone'].includes(mode)) return true;
  if (['global', 'cloudflare', 'off', 'false'].includes(mode)) return false;
  return MAINLAND_TIME_ZONES.has(browserTimeZone());
}

// EdgeOne is retired: keep the code, never route to it. Flip to false to bring
// the fallback back (and everything below it wakes up again).
const EDGEONE_FALLBACK_RETIRED = true;

function fallbackEnabled() {
  if (EDGEONE_FALLBACK_RETIRED) return false;
  return shouldProbePrimaryForFallback();
}

// Best-effort guess of whether the visitor is in mainland China, from the browser
// time zone (or an explicit override). Used only to pick the right failure
// message now that everything routes through Cloudflare.
export function isMainlandRegion() {
  const mode = fallbackRegionMode();
  if (['cn', 'china', 'mainland'].includes(mode)) return true;
  if (['global', 'cloudflare', 'off', 'false'].includes(mode)) return false;
  return MAINLAND_TIME_ZONES.has(browserTimeZone());
}

// The message to show when an Ask request fails. In mainland China the Worker is
// commonly blocked, so a failure there means the feature is regionally
// unavailable; elsewhere a failure is almost always transient, so invite a retry.
export function askErrorMessage() {
  return isMainlandRegion()
    ? 'Ask is currently unavailable in your region. 该功能在当前区域暂不可用。'
    : 'Something went wrong. Please try again.';
}

function timeoutSignal(ms) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  return { signal: controller.signal, cancel: () => clearTimeout(timer) };
}

async function probeEndpoint(url) {
  const probe = timeoutSignal(PRIMARY_PROBE_TIMEOUT_MS);
  try {
    const res = await fetch(url, {
      method: 'OPTIONS',
      cache: 'no-store',
      signal: probe.signal,
    });
    return res.ok || res.status < 500;
  } catch {
    return false;
  } finally {
    probe.cancel();
  }
}

async function endpointOrder() {
  const list = endpoints();
  if (list.length <= 1) return list;
  const primary = list[0];
  const fallbacks = list.slice(1);
  if (!fallbackEnabled()) return [primary];

  const primaryReachable = await probeEndpoint(primary);
  if (primaryReachable) return [primary];

  return fallbacks.length ? [...fallbacks, primary] : [primary];
}

async function postAsk(url, question, contexts) {
  const timeout = timeoutSignal(ASK_POST_TIMEOUT_MS);
  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ question, contexts }),
      signal: timeout.signal,
    });
    if (!res.ok || !res.body) throw new Error(`ask failed at ${url}: ${res.status}`);
    return res;
  } finally {
    timeout.cancel();
  }
}

function wait(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function postAskWithRetries(url, question, contexts, retries) {
  let lastError = null;
  for (let attempt = 0; attempt < retries; attempt += 1) {
    try {
      return await postAsk(url, question, contexts);
    } catch (err) {
      lastError = err;
      if (attempt + 1 < retries) await wait(FALLBACK_RETRY_DELAY_MS);
    }
  }
  throw lastError || new Error(`ask failed at ${url}`);
}

// Async generator yielding answer text chunks as they stream in. Parses the
// Workers AI SSE format: lines of `data: {"response":"..."}`, ending at `[DONE]`.
export async function* askStream(question, contexts) {
  const candidates = await endpointOrder();
  if (!candidates.length) throw new Error('ask endpoint not configured');
  const primary = endpoints()[0];

  let res = null;
  let lastError = null;
  for (const url of candidates) {
    try {
      const retries = url === primary ? 1 : Math.max(1, FALLBACK_POST_RETRIES);
      res = await postAskWithRetries(url, question, contexts, retries);
      break;
    } catch (err) {
      lastError = err;
    }
  }
  if (!res) throw lastError || new Error('ask failed');

  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';

  for (;;) {
    const { value, done } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });

    const events = buffer.split('\n\n');
    buffer = events.pop() || ''; // keep the trailing partial event
    for (const evt of events) {
      const line = evt.split('\n').find((l) => l.startsWith('data:'));
      if (!line) continue;
      const data = line.slice(5).trim();
      if (data === '[DONE]') return;
      try {
        const json = JSON.parse(data);
        if (json.response) yield json.response;
      } catch {
        // ignore keep-alives / non-JSON lines
      }
    }
  }
}
