<script>
import { publicationDescriptions } from '../data/publications';

export default {
  name: 'ResumeTab',
  data() {
    return {
      pubDesc: publicationDescriptions,
      isDark: false
    };
  },
  mounted() {
    this.syncThemeState();
    this._onThemeChange = () => this.syncThemeState();
    window.addEventListener('theme-change', this._onThemeChange);
  },
  unmounted() {
    window.removeEventListener('theme-change', this._onThemeChange);
    if (this._themeTransitionTimer) {
      clearTimeout(this._themeTransitionTimer);
      this._themeTransitionTimer = null;
    }
  },
  methods: {
    syncThemeState() {
      const saved = localStorage.getItem('theme');
      const prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
      const shouldBeDark = document.body.classList.contains('dark-mode') || saved === 'dark' || (!saved && prefersDark);
      document.documentElement.classList.toggle('dark-mode', shouldBeDark);
      document.body.classList.toggle('dark-mode', shouldBeDark);
      this.isDark = shouldBeDark;
      this.updateGlobalThemeIcon();
    },
    applyTheme(theme, persist = true) {
      const dark = theme === 'dark';
      document.documentElement.classList.toggle('dark-mode', dark);
      document.body.classList.toggle('dark-mode', dark);
      this.isDark = dark;
      this.updateGlobalThemeIcon();
      if (persist) {
        localStorage.setItem('theme', theme);
      }
      window.dispatchEvent(new CustomEvent('theme-change', { detail: { theme } }));
    },
    updateGlobalThemeIcon() {
      const icon = document.querySelector('#toggle-theme i');
      if (!icon) return;
      icon.classList.toggle('fa-sun', !this.isDark);
      icon.classList.toggle('fa-moon', this.isDark);
    },
    toggleTheme() {
      this.beginThemeTransition();
      this.applyTheme(this.isDark ? 'light' : 'dark');
    },
    beginThemeTransition() {
      document.documentElement.classList.add('theme-transitioning');
      document.body.classList.add('theme-transitioning');
      clearTimeout(this._themeTransitionTimer);
      this._themeTransitionTimer = setTimeout(() => {
        document.documentElement.classList.remove('theme-transitioning');
        document.body.classList.remove('theme-transitioning');
        this._themeTransitionTimer = null;
      }, 2250);
    },
    goBack() {
      // Return to wherever the visitor came from; fall back to home on a direct hit.
      if (window.history.state && window.history.state.back) {
        this.$router.back();
      } else {
        this.$router.push('/home');
      }
    },
    printPage() {
      window.print();
    }
  }
};
</script>

